def add_arguments(self, parser):
    parser.add_argument('--emulator-path', type=str, help='Path to the emulator executable')
    parser.add_argument('--emulator-args', type=str, help='Arguments to pass to the emulator')
    parser.add_argument('--emulator-log', type=str, help='Path to the emulator log file')
    parser.add_argument('--emulator-timeout', type=int, help='Timeout for the emulator in seconds')
    parser.add_argument('--emulator-debug', action='store_true', help='Enable debug mode for the emulator')
    parser.add_argument('--emulator-verbose', action='store_true', help='Enable verbose mode for the emulator')
    parser.add_argument('--emulator-headless', action='store_true', help='Run the emulator in headless mode')
    parser.add_argument('--emulator-snapshot', type=str, help='Path to the emulator snapshot file')
    parser.add_argument('--emulator-restore', action='store_true', help='Restore the emulator from a snapshot')
    parser.add_argument('--emulator-save', action='store_true', help='Save the emulator state to a snapshot')
    parser.add_argument('--emulator-fastboot', action='store_true', help='Boot the emulator into fastboot mode')
    parser.add_argument('--emulator-no-skin', action='store_true', help='Disable the emulator skin')
    parser.add_argument('--emulator-no-window', action='store_true', help='Disable the emulator window')
    parser.add_argument('--emulator-no-audio', action='store_true', help='Disable the emulator audio')
    parser.add_argument('--emulator-no-boot-anim', action='store_true', help='Disable the emulator boot animation')
    parser.add_argument('--emulator-no-snapshot-load', action='store_true', help='Disable loading the emulator snapshot')
    parser.add_argument('--emulator-no-snapshot-save', action='store_true', help='Disable saving the emulator snapshot')
    parser.add_argument('--emulator-no-cache', action='store_true', help='Disable the emulator cache')